package generators

// bridgeE2EGeneratedTemplate renders light HTTP e2e tests for one bridged
// entity hosted by a spec-mode database: a self-contained stack (testsqlite →
// spec store → repository → bridge → testserver.ServeBridge), no containers.
// Bodies reuse validCreate<E>Request from the generated validation tests
// (same package, untagged, so it is visible under -tags e2e).
const bridgeE2EGeneratedTemplate = `//go:build e2e

// Code generated by gopernicus. DO NOT EDIT.
// This file is regenerated every time 'gopernicus generate' runs.

package {{.BridgePackage}}

import (
	"context"
{{- if or .HasRecordState .CreateMaxBodySize (and .HasList .UniqueRequestFields)}}
	"encoding/json"
{{- end}}
{{- if .HasList}}
	"net/url"
{{- end}}
{{- if and .HasList .UniqueRequestFields}}
	"strconv"
{{- end}}
{{- if .CreateMaxBodySize}}
	"strings"
{{- end}}
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"

	"{{.RepoImport}}"
	"{{.StoreImport}}"
{{- if eq .AuthMode "session"}}
	"{{.ModulePath}}/core/auth/authentication/satisfiers"
	"{{.ModulePath}}/core/repositories/auth/sessions"
	"{{.ModulePath}}/core/repositories/auth/sessions/sessionspgx"
	"{{.ModulePath}}/core/repositories/auth/users"
	"{{.ModulePath}}/core/repositories/auth/users/userspgx"

	"github.com/gopernicus/gopernicus/core/auth/authentication"
{{- end}}
{{- if .HasAuthorize}}
	"github.com/gopernicus/gopernicus/core/auth/authorization"
{{- end}}

	"github.com/gopernicus/gopernicus/sdk/logger"
{{- if .BridgeAuthEnabled}}
	"github.com/gopernicus/gopernicus/workshop/testing/testauth"
{{- end}}
	"github.com/gopernicus/gopernicus/workshop/testing/testhttp"
{{- if not .SpecMode}}
	"github.com/gopernicus/gopernicus/workshop/testing/testpgx"
{{- end}}
	"github.com/gopernicus/gopernicus/workshop/testing/testserver"
{{- if .SpecMode}}
	"github.com/gopernicus/gopernicus/workshop/testing/testsqlite"
{{- end}}
{{- if or .FKSeeds (eq .AuthMode "session")}}
	"{{.FixtureImport}}"
{{- end}}
)

// Ensure imports are used.
var _ = assert.Equal

// e2eDB is the test database handle the stack boots against.
type e2eDB = {{if .SpecMode}}*testsqlite.TestSQLite{{else}}*testpgx.TestPGX{{end}}
{{- if .HasAuthorize}}{{with .AuthSchemaEntity}}

// e2eAuthSchema is the entity's resource schema, rendered locally — the
// domain composite package exports AuthSchema() but importing it here is an
// import cycle (the composite imports this bridge package). The bridge's
// own @auth.create relationship writes at POST time grant the suite's
// subject the relations these permissions check.
func e2eAuthSchema() []authorization.ResourceSchema {
	return []authorization.ResourceSchema{
		{
			Name: "{{.ResourceType}}",
			Def: authorization.ResourceTypeDef{
				Relations: map[string]authorization.RelationDef{
{{- range .Relations}}
					"{{.Name}}": {AllowedSubjects: []authorization.SubjectTypeRef{
{{- range .AllowedSubjects}}
						{Type: "{{.Type}}"{{if .Relation}}, Relation: "{{.Relation}}"{{end}}},
{{- end}}
					}},
{{- end}}
				},
				Permissions: map[string]authorization.PermissionRule{
{{- range .Permissions}}
					"{{.Name}}": authorization.AnyOf(
{{- range .Checks}}
{{- if .IsDirect}}
						authorization.Direct("{{.Relation}}"),
{{- else}}
						authorization.Through("{{.Relation}}", "{{.Permission}}"),
{{- end}}
{{- end}}
					),
{{- end}}
				},
			},
		},
	}
}
{{- end}}{{- end}}

// setupE2EServer boots the full HTTP stack for {{.EntityName}} against a fresh
// database: store → repository → bridge, served via testserver.ServeBridge.
// It returns the test DB too so FK parents can be seeded into the same store
// the server reads. migrateE2EDB is defined in e2e_test.go (bootstrap file).
func setupE2EServer(t *testing.T) (*testhttp.Client, e2eDB) {
	t.Helper()

	if testing.Short() {
		t.Skip("skipping e2e test")
	}

	ctx := context.Background()
{{- if .SpecMode}}
	db := testsqlite.SetupTestSQLite(t, ctx, testsqlite.WithMigrations(migrateE2EDB))

	store, err := {{.StorePkg}}.NewStore(db.Querier(), db.Dialect(), {{.StorePkg}}.TxRunner(db.TxRunner()))
	require.NoError(t, err)
{{- else}}
	db := testpgx.SetupTestPGX(t, ctx, testpgx.WithMigrations(migrateE2EDB))

	store := {{.StorePkg}}.NewStore(logger.NewNoop(), db.Pool)
{{- end}}
	repo := {{.RepoPkg}}.NewRepository({{.RepoPkg}}.NewCacheStore(store, nil))
{{- if .BridgeAuthEnabled}}
{{- if eq .AuthMode "session"}}
	usersRepo := users.NewRepository(users.NewCacheStore(userspgx.NewStore(logger.NewNoop(), db.Pool), nil))
	sessionsRepo := sessions.NewRepository(sessions.NewCacheStore(sessionspgx.NewStore(logger.NewNoop(), db.Pool), nil))
	authenticator, signer := testauth.AuthenticatorWithRepositories("e2etest", authentication.NewRepositories(
		satisfiers.NewUserSatisfier(usersRepo),
		nil,
		satisfiers.NewSessionSatisfier(sessionsRepo),
		nil,
		nil,
	))
{{- else if eq .AuthMode "jwt"}}
	authenticator, signer := testauth.Authenticator("e2etest")
{{- else}}
	authenticator, _ := testauth.Authenticator("e2etest")
{{- end}}
{{- if .HasAuthorize}}
	authorizer, _ := testauth.AuthorizerWithStore(authorization.NewSchema(e2eAuthSchema()))
	bridge := NewBridge(logger.NewNoop(), repo, testserver.NewRateLimiter(), authenticator, authorizer)
{{- else}}
	bridge := NewBridge(logger.NewNoop(), repo, testserver.NewRateLimiter(), authenticator, testauth.Authorizer())
{{- end}}
{{- else}}
	bridge := NewBridge(logger.NewNoop(), repo, testserver.NewRateLimiter())
{{- end}}

	client := testserver.ServeBridge(t, bridge)
{{- if eq .AuthMode "jwt"}}

	// The exercised routes authenticate via the JWT fast path (signature
	// only) — a minted token needs no database rows.
	client.SetBearerToken(testauth.MintAccessToken(signer, "e2e-test-user"))
{{- else if eq .AuthMode "session"}}

	// user_session routes recheck the session row: seed a session whose
	// stored hash matches the real minted token.
	user := {{.FixturePkg}}.CreateTestUserWithDefaults(t, ctx, db)
	token := testauth.MintAccessToken(signer, user.UserID)
	tokenHash, err := authentication.HashToken(token)
	require.NoError(t, err)
	{{.FixturePkg}}.CreateTestSession(t, ctx, db, user.UserID, map[string]any{
		"session_token_hash": tokenHash,
	})
	client.SetBearerToken(token)
{{- end}}
	return client, db
}

// seededCreate{{.EntityName}}Request builds a valid create request, populating
// foreign-key fields from parent rows seeded into db.
func seededCreate{{.EntityName}}Request(t *testing.T, db e2eDB) Create{{.EntityName}}Request {
	t.Helper()
{{- if .FKSeeds}}
	ctx := context.Background()
	req := validCreate{{.EntityName}}Request()
{{- range $i, $s := .FKSeeds}}
	parent{{$i}} := {{$.FixturePkg}}.CreateTest{{$s.ParentEntity}}WithDefaults(t, ctx, db)
	req.{{$s.RequestField}} = {{$s.ParentPKExpr}}
{{- end}}
	return req
{{- else}}
	_ = db
	return validCreate{{.EntityName}}Request()
{{- end}}
}

{{if or .CreateAuthed (and .HasGet .GetAuthed)}}
// The suite runs authenticated — one anonymous request must still be
// rejected, proving enforcement is live in this exact stack.
func TestE2E{{.EntityName}}RequiresAuthentication(t *testing.T) {
	client, db := setupE2EServer(t)
	anon := client.Anonymous()
{{- if .CreateAuthed}}
	anon.Post(t, "{{.CreatePath}}", seededCreate{{.EntityName}}Request(t, db)).RequireStatus(t, 401)
{{- else}}
	_ = db
	id := "{{.NotFoundID}}"
	anon.Get(t, {{.GetPathExpr}}).RequireStatus(t, 401)
{{- end}}
}
{{end}}
func TestE2E{{.EntityName}}CreateAndGet(t *testing.T) {
	client, db := setupE2EServer(t)

	resp := client.Post(t, "{{.CreatePath}}", seededCreate{{.EntityName}}Request(t, db))
	resp.RequireStatus(t, 201)
	id := resp.String(t, "record.{{.PKJSON}}")
	require.NotEmpty(t, id)
{{- if .HasGet}}

	got := client.Get(t, {{.GetPathExpr}})
	got.RequireStatus(t, 200)
	assert.Equal(t, id, got.String(t, "record.{{.PKJSON}}"))

	t.Run("not found", func(t *testing.T) {
		id := "{{.NotFoundID}}"
		client.Get(t, {{.GetPathExpr}}).RequireStatus(t, {{.NotFoundStatus}})
	})
{{- end}}
}
{{if .HasList}}
func TestE2E{{.EntityName}}List(t *testing.T) {
	client, db := setupE2EServer(t)

	client.Post(t, "{{.CreatePath}}", seededCreate{{.EntityName}}Request(t, db)).RequireStatus(t, 201)
	client.Get(t, "{{.ListPath}}").RequireStatus(t, 200)
}

func TestE2E{{.EntityName}}PaginationAdvance(t *testing.T) {
	client, db := setupE2EServer(t)

	// Three rows, then walk two pages of two — keyset pagination must not
	// repeat a row across the page boundary (page1 ∩ page2 = ∅).
	for i := 0; i < 3; i++ {
{{- if .UniqueRequestFields}}
		// UNIQUE-columned fields must vary per row or the insert 409s.
		raw, err := json.Marshal(seededCreate{{.EntityName}}Request(t, db))
		require.NoError(t, err)
		var body map[string]any
		require.NoError(t, json.Unmarshal(raw, &body))
{{- range .UniqueRequestFields}}
		if s, ok := body["{{.}}"].(string); ok {
			body["{{.}}"] = s + "-" + strconv.Itoa(i)
		}
{{- end}}
		client.Post(t, "{{.CreatePath}}", body).RequireStatus(t, 201)
{{- else}}
		client.Post(t, "{{.CreatePath}}", seededCreate{{.EntityName}}Request(t, db)).RequireStatus(t, 201)
{{- end}}
	}

	page1 := client.Get(t, "{{.ListPath}}?limit=2")
	page1.RequireStatus(t, 200)
	cursor := page1.String(t, "pagination.next_cursor")
	require.NotEmpty(t, cursor, "a full first page must yield a next cursor")

	page2 := client.Get(t, "{{.ListPath}}?limit=2&cursor="+url.QueryEscape(cursor))
	page2.RequireStatus(t, 200)

	seen := map[string]bool{}
	for _, row := range page1.Data(t) {
		if m, ok := row.(map[string]any); ok {
			seen[toStr(m["{{.PKJSON}}"])] = true
		}
	}
	advanced := false
	for _, row := range page2.Data(t) {
		m, ok := row.(map[string]any)
		if !ok {
			continue
		}
		pk := toStr(m["{{.PKJSON}}"])
		assert.False(t, seen[pk], "row %s appears on both pages", pk)
		advanced = true
	}
	assert.True(t, advanced, "second page should contain the remaining row")
}

func toStr(v any) string {
	s, _ := v.(string)
	return s
}
{{end}}{{if .HasDelete}}
func TestE2E{{.EntityName}}Delete(t *testing.T) {
	client, db := setupE2EServer(t)

	resp := client.Post(t, "{{.CreatePath}}", seededCreate{{.EntityName}}Request(t, db))
	resp.RequireStatus(t, 201)
	id := resp.String(t, "record.{{.PKJSON}}")
	require.NotEmpty(t, id)

	client.Delete(t, {{.DeletePathExpr}}).RequireStatus(t, 204)
{{- if .HasGet}}
	client.Get(t, {{.GetPathExpr}}).RequireStatus(t, {{.NotFoundStatus}})
{{- end}}
}
{{end}}{{if .HasList}}
func TestE2E{{.EntityName}}SQLInjection(t *testing.T) {
	client, db := setupE2EServer(t)

	// One known row — an executed OR-1=1 style injection would leak it.
	client.Post(t, "{{.CreatePath}}", seededCreate{{.EntityName}}Request(t, db)).RequireStatus(t, 201)

	payloads := []string{
		` + "`" + `' OR 1=1 --` + "`" + `,
		` + "`" + `'; DROP TABLE zzz_not_a_table; --` + "`" + `,
		` + "`" + `" OR ""="` + "`" + `,
	}

	// String filter params are parameterized match values: a payload must
	// never error the server and must never match the seeded row.
	stringParams := []string{ {{- range .StringFilterParams}}{{printf "%q" .}}, {{end -}} }
	for _, param := range stringParams {
		for _, payload := range payloads {
			resp := client.Get(t, "{{.ListPath}}?"+url.Values{param: []string{payload}}.Encode())
			require.Less(t, resp.StatusCode, 500,
				"param %q payload %q must not cause a server error", param, payload)
			if resp.StatusCode == 200 {
				// Empty result sets marshal as data: null — only a non-empty
				// array is a leak.
				if data, ok := resp.JSON(t)["data"].([]any); ok {
					assert.Empty(t, data,
						"param %q payload %q matched rows — possible injection", param, payload)
				}
			}
		}
	}

	// Non-string filters and order/limit/cursor reject or ignore garbage —
	// never a server error.
	otherParams := []string{ {{- range .OtherProbeParams}}{{printf "%q" .}}, {{end -}} "order", "limit", "cursor"}
	for _, param := range otherParams {
		for _, payload := range payloads {
			resp := client.Get(t, "{{.ListPath}}?"+url.Values{param: []string{payload}}.Encode())
			require.Less(t, resp.StatusCode, 500,
				"param %q payload %q must not cause a server error", param, payload)
		}
	}
}
{{end}}{{if .CreateMaxBodySize}}
func TestE2E{{.EntityName}}OversizedPayload(t *testing.T) {
	client, db := setupE2EServer(t)

	// A body past the route's max_body_size ({{.CreateMaxBodySize}} bytes) must
	// be rejected with 413, not accepted or 500'd. Pad a valid request with a
	// huge string field the server ignores so only the size trips the limit.
	raw, err := json.Marshal(seededCreate{{.EntityName}}Request(t, db))
	require.NoError(t, err)
	var body map[string]any
	require.NoError(t, json.Unmarshal(raw, &body))
	body["_padding"] = strings.Repeat("A", {{.CreateMaxBodySize}}+1)

	client.Post(t, "{{.CreatePath}}", body).RequireStatus(t, 413)
}
{{end}}{{if .HasRecordState}}
func TestE2E{{.EntityName}}MassAssignment(t *testing.T) {
	client, db := setupE2EServer(t)

	// A client smuggling record_state into the create body must not control
	// the stored state — the field is not part of the request model and the
	// lifecycle routes own all transitions (SEC1/P5).
	raw, err := json.Marshal(seededCreate{{.EntityName}}Request(t, db))
	require.NoError(t, err)
	var body map[string]any
	require.NoError(t, json.Unmarshal(raw, &body))
	body["record_state"] = "zzz-forged-state"

	resp := client.Post(t, "{{.CreatePath}}", body)
	resp.RequireStatus(t, 201)
	assert.NotEqual(t, "zzz-forged-state", resp.String(t, "record.record_state"))
}
{{end}}{{if and .UpdateLegitJSON .HasGet}}
func TestE2E{{.EntityName}}UpdateMassAssignment(t *testing.T) {
	client, db := setupE2EServer(t)

	resp := client.Post(t, "{{.CreatePath}}", seededCreate{{.EntityName}}Request(t, db))
	resp.RequireStatus(t, 201)
	id := resp.String(t, "record.{{.PKJSON}}")
	require.NotEmpty(t, id)

	// A PUT that edits a legit field while smuggling record_state must not
	// move the stored state — record_state is excluded from the update model
	// (SEC1), so the lifecycle routes remain the only way to transition it.
	client.Put(t, {{.UpdatePathExpr}}, map[string]any{
		"{{.UpdateLegitJSON}}": {{.UpdateLegitValue}},
		"record_state":         "zzz-forged-state",
	}).RequireStatus(t, 200)

	got := client.Get(t, {{.GetPathExpr}})
	got.RequireStatus(t, 200)
	assert.NotEqual(t, "zzz-forged-state", got.String(t, "record.record_state"))
}
{{end}}
`

// bridgeE2EBootstrapTemplate is created once: the migration hook the e2e
// stack uses, mirroring the store packages' integration bootstrap.
const bridgeE2EBootstrapTemplate = `//go:build e2e

// This file is created once by gopernicus and will NOT be overwritten.
// Add custom e2e tests for {{.EntityName}} routes here. The
// setupE2EServer() helper in generated_e2e_test.go provides a fresh stack.

package {{.BridgePackage}}

import (
	"context"
	"os"

{{- if .SpecMode}}
	"github.com/gopernicus/gopernicus/infrastructure/database/sqlite/moderncdb"
{{- else}}
	"github.com/gopernicus/gopernicus/infrastructure/database/postgres/pgxdb"
{{- end}}
	"github.com/gopernicus/gopernicus/workshop/testing/testenv"
)

// migrateE2EDB applies this project's migrations to the e2e test database.
// testenv.ProjectRoot resolves the module root, so the migrations path works
// at any test working directory.
{{- if .SpecMode}}
func migrateE2EDB(ctx context.Context, db *moderncdb.DB) error {
	root, err := testenv.ProjectRoot()
	if err != nil {
		return err
	}
	return moderncdb.RunMigrations(ctx, db, os.DirFS(root), "{{.MigrationsDir}}")
}
{{- else}}
func migrateE2EDB(ctx context.Context, pool *pgxdb.Pool) error {
	root, err := testenv.ProjectRoot()
	if err != nil {
		return err
	}
	return pgxdb.RunMigrations(ctx, pool, os.DirFS(root), "{{.MigrationsDir}}")
}
{{- end}}
`
